const BASE='https://services.leadconnectorhq.com';
const LOCATION='TW8JsPW5NMnA3tfK2XLn';
const TOKEN=process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const headers={Authorization:`Bearer ${TOKEN}`,Version:'2021-07-28','Content-Type':'application/json'};

async function req(method,path,body){
  const r=await fetch(BASE+path,{method,headers,body:body?JSON.stringify(body):undefined});
  const t=await r.text(); let j={};
  try{j=t?JSON.parse(t):{}}catch{j={raw:t}}
  if(!r.ok) throw new Error(`${method} ${path} -> ${r.status} ${t.slice(0,300)}`);
  return j;
}
const toMs=v=>{const n=Number(v); if(!Number.isFinite(n)||n<=0) return 0; return n<1e12?n*1000:n;};
const daysAgo=(ms)=> (Date.now()-ms)/86400000;

(async()=>{
  if(!TOKEN){ console.log('Guardrail: missing GHL token.'); return; }

  const now=Date.now();
  const out={scanned:0,eligibleMid:0,eligibleHigh:0,tagsApplied:0,stageNudges:0,tasksCreated:0,urgent:false,urgentCount:0,top:[],errors:[]};

  const pipes=await req('GET',`/opportunities/pipelines?locationId=${LOCATION}`);
  const pipeline=(pipes.pipelines||[])[0];
  if(!pipeline) throw new Error('No pipeline found');

  const stageByName={};
  for(const s of (pipeline.stages||[])) stageByName[String(s.name||'').toLowerCase()]=s.id;
  const stageNames={
    newLead:'new lead', abandoned:'abandoned cart', ebook:'ebook buyer', course:'course buyer', lite:'lite buyer',
    membership:'membership active', backend:'backend prospect', intensiveApplied:'intensive applied'
  };
  const id={}; for(const [k,n] of Object.entries(stageNames)) id[k]=stageByName[n];

  const oppRes=await req('GET',`/opportunities/search?location_id=${LOCATION}&pipeline_id=${pipeline.id}&limit=100`);
  const opps=oppRes.opportunities||[];

  let conv=[];
  for(const p of [`/conversations/search?locationId=${LOCATION}&limit=100`,`/conversations/search?location_id=${LOCATION}&limit=100`]){
    try{ const r=await req('GET',p); if(Array.isArray(r.conversations)){ conv=r.conversations; break; } }catch{}
  }
  const convByContact=new Map();
  for(const c of conv){
    const cid=c.contactId||c.contact_id; if(!cid) continue;
    const arr=convByContact.get(cid)||[]; arr.push(c); convByContact.set(cid,arr);
  }

  let appts=[];
  for(const p of [`/appointments/?locationId=${LOCATION}&limit=100`,`/appointments/?location_id=${LOCATION}&limit=100`]){
    try{ const r=await req('GET',p); appts=r.appointments||r.data||[]; if(Array.isArray(appts)) break; }catch{}
  }
  const apptByContact=new Map();
  for(const a of appts){
    const cid=a.contactId||a.contact_id; if(!cid) continue;
    const arr=apptByContact.get(cid)||[]; arr.push(a); apptByContact.set(cid,arr);
  }

  const midTag='upsell-midticket-ready';
  const highTag='upsell-highticket-ready';
  const nowIso=new Date(now).toISOString();

  for(const o of opps){
    const contactId=o.contactId||o.contact_id; if(!contactId) continue;
    const stageId=o.pipelineStageId||o.pipeline_stage_id;
    if(![id.ebook,id.course,id.lite,id.membership,id.backend,id.intensiveApplied].includes(stageId)) continue;

    out.scanned++;
    const added=toMs(o.dateAdded||o.date_added||o.createdAt||o.created_at);
    const ageDays=added?daysAgo(added):999;

    const clist=convByContact.get(contactId)||[];
    let recentConv=0, recentInbound=0;
    for(const c of clist){
      const last=toMs(c.lastMessageDate||c.last_message_date||c.dateUpdated||c.date_updated||c.dateAdded||c.date_added);
      if(last && (now-last)<=7*86400000) recentConv++;
      if(String(c.lastMessageType||c.last_message_type||'').toLowerCase().includes('inbound') && last && (now-last)<=7*86400000) recentInbound++;
    }

    const alist=apptByContact.get(contactId)||[];
    let bookedOrConfirmed=0, completed=0, noShowOrCancel=0;
    for(const a of alist){
      const s=String(a.appointmentStatus||a.status||'').toLowerCase();
      if(s.includes('book')||s.includes('confirm')) bookedOrConfirmed++;
      if(s.includes('complete')||s.includes('showed')) completed++;
      if(s.includes('no-show')||s.includes('noshow')||s.includes('cancel')) noShowOrCancel++;
    }

    const midCandidate = [id.ebook,id.lite,id.course].includes(stageId)
      && ageDays>=1 && ageDays<=45
      && (recentConv>=1 || recentInbound>=1 || bookedOrConfirmed>=1)
      && noShowOrCancel<2;

    const highCandidate = ([id.membership,id.course,id.backend].includes(stageId) && ageDays>=3 && ageDays<=90)
      && ((recentInbound>=1 && recentConv>=1) || completed>=1 || (bookedOrConfirmed>=2))
      && noShowOrCancel<2;

    if(!midCandidate && !highCandidate) continue;

    const c=await req('GET',`/contacts/${contactId}`);
    const existing=(c.contact?.tags||c.tags||[]).map(x=>String(x).toLowerCase());

    const addTags=[];
    if(midCandidate && !existing.includes(midTag)) addTags.push(midTag), out.eligibleMid++;
    if(highCandidate && !existing.includes(highTag)) addTags.push(highTag), out.eligibleHigh++;
    if(addTags.length){ await req('POST',`/contacts/${contactId}/tags`,{tags:addTags}); out.tagsApplied+=addTags.length; }

    // Route-stage nudge: only for high intent and not already backend/intensive
    if(highCandidate && id.backend && ![id.backend,id.intensiveApplied].includes(stageId)){
      try{
        await req('PUT',`/opportunities/${o.id}`,{pipelineId:pipeline.id,pipelineStageId:id.backend,locationId:LOCATION,name:o.name,status:o.status||'open',monetaryValue:o.monetaryValue||o.monetary_value||undefined});
        out.stageNudges++;
      }catch(e){ out.errors.push(`stage-nudge ${o.id}: ${e.message}`); }
    }

    // Follow-up task (idempotent-ish via title stamp day)
    const offerPath = highCandidate ? 'High-ticket coaching (Implementation Intensive)' : 'Mid-ticket community (AI Operators Circle)';
    const evidence = `age=${Math.round(ageDays)}d, recentConv=${recentConv}, recentInbound=${recentInbound}, booked=${bookedOrConfirmed}, completed=${completed}, noShowCancel=${noShowOrCancel}`;
    try{
      await req('POST',`/contacts/${contactId}/tasks`,{
        title:`Upsell follow-up: ${highCandidate?'High-ticket':'Mid-ticket'} readiness`,
        body:`Recommended path: ${offerPath}. Evidence: ${evidence}. Created ${nowIso}. No outbound sent by automation.`,
        dueDate:new Date(now+6*60*60*1000).toISOString(),
        completed:false
      });
      out.tasksCreated++;
    }catch(e){ out.errors.push(`task ${contactId}: ${e.message}`); }

    if(highCandidate){
      out.urgentCount++;
      out.top.push({contactId,oppId:o.id,name:o.name||'',evidence});
    }
  }

  out.urgent = out.urgentCount>=3;

  const lines=[];
  lines.push(`L2 Upsell Timing run complete: scanned ${out.scanned} buyer-stage opportunities.`);
  lines.push(`Eligible: ${out.eligibleMid} mid-ticket, ${out.eligibleHigh} high-ticket.`);
  lines.push(`Actions: ${out.tagsApplied} readiness tags, ${out.stageNudges} route-stage nudges, ${out.tasksCreated} follow-up tasks. No outbound messages/invoices sent.`);
  if(out.urgent){
    lines.push(`URGENT: High-intent cluster detected (${out.urgentCount}). Top opportunities:`);
    for(const t of out.top.slice(0,5)) lines.push(`- ${t.name||t.contactId} (contact ${t.contactId}, opp ${t.oppId}): ${t.evidence}`);
  }
  if(out.errors.length) lines.push(`Non-blocking API issues: ${out.errors.length} (sample: ${out.errors[0]})`);
  console.log(lines.join('\n'));
})().catch(e=>{ console.log(`L2 Upsell Timing failed: ${e.message}`); process.exit(1); });
